// OTF component registry — metadata for search, navigation, and detail pages

export const STORYBOOK_URL = 'https://otf-storybook.pages.dev'
export const NATIVE_STORYBOOK_URL = 'https://otf-ui-native-storybook.pages.dev'
// Phone-framed preview shell — wraps the native storybook in a Manus-style
// iPhone mockup. Pass `?src=<storybook URL>` to load a specific component
// route inside the frame. Used by the components/[slug] preview tab.
export const NATIVE_STORYBOOK_PREVIEW_URL = 'https://otf-ui-native-storybook-preview.pages.dev'

export type ComponentMeta = {
  slug: string
  name: string
  description: string
  category: 'Display' | 'Input' | 'Feedback' | 'Layout' | 'Data'
  tags: string[]
  /** Which platform stack the component targets. Web uses Storybook iframe; mobile uses iPhone SVG mockup. */
  stack: 'web' | 'mobile'
  hasExample?: boolean
  /** Storybook story ID — if set, preview embeds the live Storybook iframe */
  storybookId?: string
  /** Mobile only — category segment of the @otf/ui-native storybook route (primitives | interface | layouts | patterns) */
  nativeCategory?: 'primitives' | 'interface' | 'layouts' | 'patterns'
  /** Mobile only — slug segment of the @otf/ui-native storybook route */
  nativeSlug?: string
}

// ─── Storybook 8 sanitize algorithm ──────────────────────────────────────────
// 1. toLowerCase()
// 2. Replace [ '–—―′¿'!.] → '-'   (space becomes hyphen)
// 3. Remove  [&/\#,+()`$~%.'":*?<>{}]  (slash is REMOVED, not → '-')
// 4. Collapse -+  →  -
// 5. Trim leading/trailing -
//
// Key:  'Data Display' → 'data-display'   (space → hyphen)
//       'Primitives/Button' → 'primitivesbutton'  (/ removed, no hyphen!)
//       'Charts/AreaChart'  → 'chartsareachart'
//       'Data/DataGrid'     → 'datadatagrid'
//       'Forms/Controls'    → 'formscontrols'
//
// Story name uses startCase first:  DataTableStory → 'Data Table Story' → 'data-table-story'
//                                   StepperStep1   → 'Stepper Step 1'  → 'stepper-step-1'
// ─────────────────────────────────────────────────────────────────────────────

